export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:10。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗房。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室後面的暗房。平時只有文檔組的人來沖照片，校慶早上沒有人會進來。紅色安全燈把整個房間染成暗琥珀色，沖片槽和晾曬架沿牆排開，空氣裡是定影液和停影液混在一起的酸味。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠在放大機桌邊。許星棠站在門旁，背靠著牆，相機抱在胸前。她帶了韓越來。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門推開了。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越走進來。校服外罩沾灰塵的深色外套。脖子上的舞台組臨時通行證被雨打濕過，藍底白字有點糊。手背上的刮傷結了暗紅薄痂。他看見顧言的第一眼——下巴抬了一下。嘴唇壓緊。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個表情顧言見過。第七輪，鐘樓簷下，韓越用同樣的臉對他說「這樣你滿意了」。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "他也在。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "聽他說完。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "聽他說什麼。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "上次他說的每一句話，最後都變成妳一個人走進去。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的聲音不大。但每個字都帶著壓住的力道。像一根繃到極限的繩子，還沒斷，但已經在震。他沒有看顧言。他看許星棠。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他還在氣。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是氣我測他。是氣上一輪的結果——他給了假情報，我用了，最後還是失敗了。他以為是他的錯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但不是。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "上一輪的結果不是你的問題。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "沒人問你。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "鐘樓線沒有因為你的假情報出現新陷阱。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我去看過。天線屋沒有新增封鎖。沒有校安。什麼都沒有。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的眼神動了一下。從許星棠移到顧言。移回來。又移過去。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "醫務室線完整命中。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "三條假情報，只有邵叔聽過完整版本的那條命中了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你不是洩密的人。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗房裡安靜了。紅色安全燈嗡了一聲。定影液的酸味在密閉空間裡轉。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越沒有說話。他的手插在外套口袋裡。肩膀的線條繃著。通行證在他脖子上晃了一下——不是風，是他深呼吸的時候胸腔撐開了。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不信我。但他不反駁了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "問題出在邵叔。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個字。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的手從口袋裡抽出來了。不是要動手。是——整個人僵了半秒。像聽見了一個不應該出現在這個房間裡的名字。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯什麼。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "邵啟明。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "安保聯絡官。校慶安全負責人。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "22:50 以後台清場名義離開指揮區。22:58 用安全權限打開設備通道的門。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "開門的人是他。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越看著他。看著許星棠。又看回他。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的表情變了。不是憤怒。不是震驚。是——一種更冷的東西。像一塊鐵被澆了水，表面不動，裡面在收縮。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "邵叔。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "照顧你的那個。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你怎麼確定。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第七輪。三條假情報。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "只有他聽過的那條命中了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "醫務室。二號冰敷櫃。紅色盤點標籤。校安失物保管袋。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "全部命中。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越沉默了。很久。暗房裡只有紅色安全燈的嗡響和三個人的呼吸。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不是被顧言說服的。他沒有被說服。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他是被「邵叔」這兩個字嚇到的。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他怕了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是怕邵叔這個人。是怕——如果連照顧顧言七年的人都是兇手，那這件事比他以為的大太多了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他一直以為敵人是某個校外的人。某個會從外面闖進來的人。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在被告訴他——敵人一直在裡面。穿著制服。掛著警銜。拍著學生的肩膀。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你說要假死。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音變了。比剛才低。比剛才平。平到像在念一個已經決定了的事——但他還在念，說明他還沒有放棄。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你上次差點每一步都害死她。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "這次還要演死？", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你瘋了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "可能。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越盯著他。三秒。五秒。紅色安全燈把他的臉染成暗銅色。刮傷的薄痂在那種光下看起來像生鏽。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他做了一個顧言沒預料到的動作——他轉頭看許星棠。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "妳信他？", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他知道的東西比我多。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "來源我不知道。但東西是真的。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的下巴收了一下。嘴唇壓緊。他看著許星棠，又看顧言，又看回許星棠。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不是在決定信不信顧言。他是在決定——要不要因為許星棠信了，就把自己也押進去。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "鐘樓。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你要在鐘樓假死。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "然後去哪裡。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "禮堂。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "鐘樓到禮堂。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你走哪條路。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯對。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是缺的那一塊。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道怎麼假死。我知道邵叔會怎麼反應。我知道許星棠要站在哪裡。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但鐘樓到禮堂——我沒有路。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）鐘樓背面是封閉維修庭院。正面是操場。側面是舊教學樓。沒有一條是能在停電和暴雨裡快速走的。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯除非他知道。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不知道。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "那你怎麼到禮堂。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你告訴我。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越看了他一眼。那一眼裡有很多東西——氣、怕、不甘心、還有一點點被需要的東西。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他開口了。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "鐘樓後面不是死路。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "維修庭院旁邊有一條器材服務走廊。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "通到舊器材倉。再接禮堂側台卸貨口。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說這些話的時候語速變了。不是更快。是更穩。像在背一條走過很多次的路。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "平常上鎖。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "但今天舞台組搬備用燈架開過一次。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "鎖沒有重新掛。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這條路不是秘密通道。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是校慶舞台組合理使用的戶外服務動線。韓越搬過燈架。他知道鎖的狀態。他知道走向。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這不是駭客知識。是一個搬器材的人知道的事。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我能讓你過去。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "但只能一次。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最後四個字。他看著顧言說的。不是威脅。是警告。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只能一次。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為第二次走同一條路，會有人注意到。鎖會被重新掛上。或者有人會查誰開過。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一次。夠了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "夠了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "道具呢。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你負責。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "什麼道具。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "黑雨衣。我的背包。一個重量接近人形的器材包。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "舞台假人或人形支架。幾個裝沙的器材袋。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "從鐘樓背面低層維修平台墜入維修庭院。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越聽著。他的表情沒有鬆開。但他的手從口袋裡抽出來了——不是要動手。是在算。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "黑雨衣校慶到處有。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "舞台假人器材室有兩個。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "沙袋不用找，燈架配重就是。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你的背包——", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你要把自己的背包放進去。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "手機呢。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "也放進去。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越沉默了。他看著顧言。那雙在紅光裡很亮的眼睛，第一次不是在氣、不是在怕——是在確認。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你把手機放進去。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你就沒有手機了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "23:00 之後你怎麼看時間。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不需要我看。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "星棠的手機。直播控制台。禮堂數位鐘。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我的手機只能在鐘樓。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越看了許星棠一眼。許星棠沒有說話。但她點了一下頭——和剛才在走廊上一樣輕、一樣短。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越吸了一口氣。定影液的味道鑽進鼻腔。他沒有咳。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我負責什麼。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他進來了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他沒有說「我信你」。他沒有說「好」。他說的是「我負責什麼」。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這就是他的「好」。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "五件事。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第一。舞台道具假人和器材假包。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第二。黑雨衣和我的背包替換。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第三。鐘樓背面維修庭院的遠距視角布置。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第四。服務走廊和禮堂側台退路。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第五。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "23:00 前。保持星棠身邊一條實體退路。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越一條一條聽完。沒有打斷。他的手背上的刮傷在紅光下一動一動——不是傷口在動，是他的拳頭在鬆開又握緊。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "第五條。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我貼著她。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "她不進死角。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我不需要你貼著。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "妳不需要。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "但門需要有人留著。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他一眼。很短。不到一秒。但她沒有反駁。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗房裡安靜了。三個人。紅色安全燈。定影液的酸味。門外遠處傳來校慶廣播的尾音，被厚門隔成嗡嗡的低頻。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三個人了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第七輪結束的時候，只有我和星棠。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在多了一個韓越。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不是因為信我才來的。他是因為——如果邵叔真的是兇手，許星棠一個人撐不過今晚。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他怕的不是死。他怕的是她死。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯夠了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "08:40。舊社團室。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "三條規則。物件分流。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "全部寫清楚。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你真的要演死。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "那你最好別真的死了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說完轉身推開暗房的門。灰色的光從門縫切進來，把紅色切成兩半。他的背影在校服外套下繃得很直。通行證在脖子上一晃一晃。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他在門口停了半秒。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "08:40。我到。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門關上了。紅光重新把房間填滿。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著關上的門。然後看顧言。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他會來。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你還沒有解釋你是怎麼知道這些的。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "08:40。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "一起說。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他最後一眼。然後她把相機重新掛回脖子上。帶子勒進背心肩線裡。藍色工作證在紅光下變成了暗紫色。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她推開門。走了。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言一個人留在暗房裡。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "紅色安全燈嗡了一聲。定影液的味道慢慢沉下來。他低頭看自己的手。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "還在抖。但比早上好了。比 07:05 好了。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯三個人。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一次有三個人。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前七輪，我一個人。或者我和星棠兩個人。或者我和邵叔——那不算。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪——", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越說「只能一次」。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一次就夠了。", background: Background.Chapter_8_Ch8_Act2_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "08:20。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他推開暗房的門。灰色的光灌進來。走廊上有人在搬校慶看板。廣播在播百年校史展全天開放。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一切都在流程裡。一切都很正常。", background: Background.Chapter_8_Ch8_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "除了三個學生知道，今晚這個流程裡會有一個人「死」在鐘樓。", background: Background.Chapter_8_Ch8_Act2_S0 },
];
